def validate_user(data: dict) -> dict:
    """
    Validate user data and return cleaned version.

    Rules:
    - email: required, must contain @
    - age: optional, must be 0-120 if present
    - name: required, strip whitespace
    - tags: optional list, remove duplicates

    Raises ValueError with clear message if validation fails.
    """
    if not isinstance(data, dict):
        raise ValueError("Input must be a dictionary")

    cleaned = {}

    # Validate email (required)
    if 'email' not in data:
        raise ValueError("email is required")

    email = data['email']
    if not isinstance(email, str) or '@' not in email:
        raise ValueError("email must be a string containing '@'")

    cleaned['email'] = email

    # Validate name (required)
    if 'name' not in data:
        raise ValueError("name is required")

    name = data['name']
    if not isinstance(name, str):
        raise ValueError("name must be a string")

    cleaned['name'] = name.strip()

    # Validate age (optional)
    if 'age' in data:
        age = data['age']
        if not isinstance(age, (int, float)):
            raise ValueError("age must be a number")

        if age < 0 or age > 120:
            raise ValueError("age must be between 0 and 120")

        cleaned['age'] = age

    # Validate tags (optional)
    if 'tags' in data:
        tags = data['tags']
        if not isinstance(tags, list):
            raise ValueError("tags must be a list")

        # Remove duplicates while preserving order
        seen = set()
        unique_tags = []
        for tag in tags:
            if tag not in seen:
                seen.add(tag)
                unique_tags.append(tag)

        cleaned['tags'] = unique_tags

    return cleaned


# Example usage and tests
if __name__ == "__main__":
    # Valid cases
    print(validate_user({
        'email': 'user@example.com',
        'name': '  John Doe  ',
        'age': 25,
        'tags': ['python', 'coding', 'python', 'testing']
    }))
    # Output: {'email': 'user@example.com', 'name': 'John Doe', 'age': 25, 'tags': ['python', 'coding', 'testing']}

    print(validate_user({
        'email': 'jane@test.org',
        'name': 'Jane'
    }))
    # Output: {'email': 'jane@test.org', 'name': 'Jane'}

    # Invalid cases (will raise ValueError)
