        return ProcessingResult(success=True, score=result)

    except UserNotFoundError as e:
        logger.warning(f"User not found: {user_id}")
        return ProcessingResult(
            success=False,
            error=f"User {user_id} does not exist",
            error_type="USER_NOT_FOUND"
        )

    except ProfileFetchError as e:
        logger.error(f"Profile fetch failed for user {user_id}: {e}")
        return ProcessingResult(
            success=False,
            error=f"Failed to fetch profile: {str(e)}",
            error_type="API_FAILURE"
        )

    except InvalidDataError as e:
        logger.error(f"Invalid profile data for user {user_id}: {e}")
        return ProcessingResult(
            success=False,
            error=f"Profile data is invalid or incomplete: {str(e)}",
            error_type="INVALID_DATA"
        )

    except CalculationError as e:
        logger.error(f"Score calculation failed for user {user_id}: {e}")
        return ProcessingResult(
            success=False,
            error=f"Failed to calculate score: {str(e)}",
            error_type="CALCULATION_ERROR"
        )

    except Exception as e:
        # Catch-all for unexpected errors
        logger.exception(f"Unexpected error processing user {user_id}")
        return ProcessingResult(
