def merge_configs(*configs: dict, strategy: str = "last") -> dict:
    """
    Merge multiple config dicts with conflict resolution.

    Strategies:
    - "first": keep first value seen
    - "last": keep last value seen
    - "sum": sum numeric values

    Raises ValueError for invalid strategy.
    """
    valid_strategies = {"first", "last", "sum"}
    if strategy not in valid_strategies:
        raise ValueError(f"Invalid strategy '{strategy}'. Must be one of {valid_strategies}")

    if not configs:
        return {}

    result = {}

    for config in configs:
        if not isinstance(config, dict):
            raise TypeError(f"All configs must be dicts, got {type(config).__name__}")

        for key, value in config.items():
            if key not in result:
                # First time seeing this key
                result[key] = value
            else:
                # Key already exists - apply strategy
                if strategy == "first":
                    # Keep existing value (do nothing)
                    pass
                elif strategy == "last":
                    # Overwrite with new value
                    result[key] = value
                elif strategy == "sum":
                    # Sum numeric values
                    existing = result[key]
                    if isinstance(existing, (int, float)) and isinstance(value, (int, float)):
                        result[key] = existing + value
                    else:
                        raise TypeError(
                            f"Strategy 'sum' requires numeric values, "
                            f"got {type(existing).__name__} and {type(value).__name__} for key '{key}'"
                        )

    return result


# Example usage and tests
