    print("First strategy:", merged)
    # {'host': 'localhost', 'port': 8000, 'debug': True, 'timeout': 30, 'workers': 4}

    # Test "sum" strategy
    usage1 = {"cpu": 50, "memory": 100, "requests": 1000}
    usage2 = {"cpu": 30, "memory": 150, "requests": 2000}
    usage3 = {"cpu": 20, "memory": 75, "requests": 500}

