def process_data(items):
    def calculate_score(item):
        return {**item, 'score': item['value'] * 2}

    def is_active(item):
        return item['active']

    def score_above_threshold(item):
        return item['score'] > 10

    def extract_result(item):
        return {'id': item['id'], 'score': item['score']}

    from functools import reduce

    pipeline = [
        lambda data: filter(is_active, data),
        lambda data: map(calculate_score, data),
        lambda data: filter(score_above_threshold, data),
        lambda data: map(extract_result, data),
        lambda data: sorted(data, key=lambda x: x['score'], reverse=True)
    ]

    return reduce(lambda data, fn: fn(data), pipeline, items)
```

